<?php
 declare(strict_types=1); namespace tapmeppe\composer\summons; use Symfony\Component\Console\Command\Command; use Symfony\Component\Console\Input\InputArgument; use Symfony\Component\Console\Input\InputInterface; use Symfony\Component\Console\Input\InputOption; use Symfony\Component\Console\Output\OutputInterface; class Role extends \tapmeppe\composer\helpers\Summon { protected static $defaultName = 'governance:role'; protected function configure(): void { $this ->describe('This command is used to create roles.') ->addArgument('name', InputArgument::OPTIONAL, 'The role name. If unset the label will be used as basis.') ->addOption('label', 'l', InputOption::VALUE_OPTIONAL, 'The role label.') ->addOption('permissions', 'p', InputOption::VALUE_OPTIONAL, 'The list of permissions. They must be separated by a comma.'); } protected function execute(InputInterface $input, OutputInterface $output): int { $parameters = (object) $this->getParameters($input, ['label'], ['name', 'permissions']); $parameters->label = trim($parameters->label); $parameters->name = strtolower(preg_replace("/[\W_]+/", '_', $parameters->name ?: $parameters->label)); if ($role = $this->app->dataStorage->findOne('system/roles', ['name' => $parameters->name])) { $this->app->dataStorage->update('system/roles', ['_id' => $role['_id']], [ 'label' => $parameters->label ?: $role['label'], 'name' => $parameters->name, 'permissions' => $parameters->permissions ? explode(',', $parameters->permissions) : $role['permissions'], ]); $output->writeln("<info>[✓]</info> The role '{$parameters->name}' has been updated."); } else { $this->app->dataStorage->insert('system/roles', [ 'label' => $parameters->label, 'name' => $parameters->name, 'permissions' => explode(',', $parameters->permissions), ]); $output->writeln("<info>[✓]</info> The role '{$parameters->name}' has been created."); } return Command::SUCCESS; } } 